function renderIcons() {
    document.querySelectorAll('.fa-solid, .fa-spin').forEach(el => {
        // Skip if already converted to SVG
        if (el.tagName.toLowerCase() === 'svg') return;

        let iconName = null;
        let isSpin = false;
        
        for (const cls of el.classList) {
            if (cls.startsWith('fa-') && cls !== 'fa-solid' && cls !== 'fa-spin') {
                iconName = cls.substring(3);
            }
            if (cls === 'fa-spin') isSpin = true;
        }

        if (iconName && FA_ICONS[iconName]) {
            const temp = document.createElement('div');
            temp.innerHTML = FA_ICONS[iconName];
            const svg = temp.querySelector('svg');
            
            // Preserve classes
            svg.setAttribute('class', el.className);
            
            // Preserve inline styles
            if (el.getAttribute('style')) {
                svg.setAttribute('style', el.getAttribute('style'));
            }
            
            // Preserve id
            if (el.id) {
                svg.id = el.id;
            }
            
            // Add specific CSS for SVG scaling
            svg.style.height = '1em';
            svg.style.verticalAlign = '-0.125em';
            
            if (isSpin) {
                svg.style.animation = 'fa-spin 2s infinite linear';
            }
            
            el.replaceWith(svg);
        }
    });
}

// Global animation style for spinners
const style = document.createElement('style');
style.textContent = `
@keyframes fa-spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}
svg.fa-spin {
  animation: fa-spin 2s infinite linear;
}
`;
document.head.appendChild(style);

window.renderIcons = renderIcons;
document.addEventListener('DOMContentLoaded', renderIcons);
